/**
 * ACP backend definition table for /agent hot-swap (SPEC-acp-hot-swap).
 *
 * Backends live in ${MEMORY_DIR}/config/acp-providers.json so each machine
 * keeps its own command lines (npx package forms, local shims, …):
 *
 *   {
 *     "kiro":   { "command": "kiro-cli acp", "label": "Kiro CLI" },
 *     "claude": { "command": "npx claude-agent-acp", "label": "Claude Code",
 *                 "model": "claude-fable-5", "effort": "high" },
 *     "codex":  { "command": "npx @zed-industries/codex-acp", "label": "Codex" }
 *   }
 *
 * `model` / `effort` are per-backend pins sent via session/set_config_option
 * after session/new (the only way that works for claude-agent-acp — its CLI
 * flags are ignored in ACP server mode). When the file is missing or empty
 * the table degrades to a single "default" entry mirroring the .env agent,
 * so /agent stays functional (list + no-op switch) without configuration.
 */
import { readFileSync } from "node:fs";
import { config, resolveBridgeConfigPath } from "./config.js";
import { detectAgentConfigDir } from "./memory.js";

export interface AcpBackendDef {
  /** Table key — what the user types after /agent. */
  key: string;
  command: string;
  args: string[];
  label: string;
  /** Optional per-backend model pin (fuzzy alias ok, e.g. "fable-5"). */
  model?: string;
  /** Optional per-backend reasoning-effort pin ("low"/"medium"/"high"). */
  effort?: string;
}

export const DEFAULT_BACKEND_KEY = "default";

interface RawEntry {
  command?: string;
  label?: string;
  model?: string;
  effort?: string;
}

/**
 * Pure parser — no disk / env access so smoke scripts can exercise it.
 * Entries without a usable command string are skipped. `agentName` replays
 * buildAgent()'s ACP_AGENT_NAME → `--agent <name>` append for kiro commands
 * (the only CLI that takes --agent), so table entries don't lose it.
 */
export function parseAcpProviders(
  raw: string,
  agentName?: string,
): Record<string, AcpBackendDef> {
  const json = JSON.parse(raw) as Record<string, RawEntry>;
  const out: Record<string, AcpBackendDef> = {};
  for (const [key, entry] of Object.entries(json)) {
    if (!entry || typeof entry.command !== "string" || entry.command.trim() === "") continue;
    const parts = entry.command.trim().split(/\s+/);
    const command = parts[0];
    const args = parts.slice(1);
    if (agentName && command.toLowerCase().includes("kiro") && !args.includes("--agent")) {
      args.push("--agent", agentName);
    }
    out[key] = {
      key,
      command,
      args,
      label: entry.label?.trim() || key,
      model: entry.model?.trim() || undefined,
      effort: entry.effort?.trim() || undefined,
    };
  }
  return out;
}

/** Fallback table when acp-providers.json is missing/empty: the .env agent. */
export function defaultBackends(): Record<string, AcpBackendDef> {
  return {
    [DEFAULT_BACKEND_KEY]: {
      key: DEFAULT_BACKEND_KEY,
      command: config.agent.command,
      args: [...config.agent.args],
      label: `${config.agent.command}（.env 預設）`,
      model: config.acpModel || undefined,
      effort: config.acpEffort || undefined,
    },
  };
}

/** Resolved read path (MEMORY_DIR/config first, AGENT_CONFIG_DIR fallback). */
