// 重現 /agent（無參數）的回覆內容，並用相同 parse_mode 對 Telegram API 實測。
// 跑法：cd G:/AI/telegram-kiro-bridge-main && npx tsx C:/Users/jiunchiwang/AppData/Local/Temp/repro-agent-noarg.mjs
// 先清掉空字串環境變數（#4017 教訓），再讓 dotenv 載入 .env
for (const k of Object.keys(process.env)) {
  if (process.env[k] === "") delete process.env[k];
}
await import("dotenv/config");

const { loadAcpProviders, acpProvidersConfigPath, DEFAULT_BACKEND_KEY } =
  await import("G:/AI/telegram-kiro-bridge-main/src/acp-providers.ts");
const { config } = await import("G:/AI/telegram-kiro-bridge-main/src/config.ts");

// 複製 agent.ts describeCurrent（模擬「有 acp session、無 backend key」= .env 預設）
function describeCurrent(activeProvider, acpBackend) {
  if (!activeProvider) return `(尚無 session — 下一則訊息會用 .env 預設 ${config.agent.command} 開啟)`;
  if (activeProvider !== "acp") return `Direct API provider \`${activeProvider}\`（用 /model 管理）`;
  if (acpBackend) {
    const def = loadAcpProviders()[acpBackend];
    return def ? `**${def.label}**（\`${acpBackend}\`）` : `\`${acpBackend}\`（設定檔已無此項）`;
  }
  return `.env 預設（${config.agent.command} ${config.agent.args.join(" ")}）`;
}

const backends = loadAcpProviders();
const isEnvFallbackOnly =
  Object.keys(backends).length === 1 && backends[DEFAULT_BACKEND_KEY] !== undefined;

// 兩種 session 狀態都建：現役 acp session（無 backend key）與尚無 session
const variants = {
  "active-env-default": { activeProvider: "acp", acpBackend: undefined },
  "no-session": undefined,
};

const token = process.env.TELEGRAM_BOT_TOKEN;
const chatId = 509424983;

for (const [name, session] of Object.entries(variants)) {
  const current = describeCurrent(session?.activeProvider, session?.acpBackend);
  const lines = [
    `🤖 當前 agent：${current}`,
    "",
    "可用 agent：",
    ...Object.values(backends).map((b) => {
      const marker =
        session?.activeProvider === "acp" && session?.acpBackend === b.key ? " ← 當前" : "";
      const pin = b.model ? `，pin ${b.model}${b.effort ? `/${b.effort}` : ""}` : "";
      return `• \`${b.key}\` — ${b.label}（${b.command} ${b.args.join(" ")}${pin}）${marker}`;
    }),
    "",
    "用法：`/agent <名稱>` 切換（自動交接對話摘要，不掉記憶）",
    "切 Direct API 請用 /model。",
  ];
  if (isEnvFallbackOnly) {
    lines.push(
      "",
      `⚠️ 尚未建立 backend 設定檔，目前只有 .env 預設 agent。`,
      `建立 ${acpProvidersConfigPath()} 後即可多 agent 切換。`,
    );
  }
  const text = lines.join("\n");
  console.log(`\n===== variant: ${name} =====`);
  console.log(text);

  if (name !== "active-env-default") continue; // 只實測最貼近實況的一種，避免重複打擾
  const res = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({
      chat_id: chatId,
      text,
      parse_mode: "Markdown",
      disable_notification: true,
    }),
  });
  const body = await res.text();
  console.log(`\n>>> sendMessage(parse_mode=Markdown) HTTP ${res.status}`);
  console.log(body.slice(0, 500));
}

